INSERT INTO "product" ("id", "name", "cat_name", "category_id", "sub_category_id", "brand_id", "price", "orig", "badge", "img", "desc", "sizes", "colors", "size_chart", "product_type", "stock_status", "is_featured", "materials", "care", "is_best_seller", "is_new_arrival", "seo_title", "seo_description", "focus_keyword", "meta_keywords", "product_tags") VALUES ('minimalist-chain', 'Black Starfish Anti Tarnish Pendant Set', 'Necklaces', 28, NULL, 1, '₹780', '₹1,560', 'New Arrival', 'https://res.cloudinary.com/dnetvfdvs/image/upload/v1780393650/dadson/products/mixfkerzksffzmtkmume.jpg', 'Add a touch of luxury to your jewelry collection with this beautifully crafted DADSON Jewelry piece. Made for women who love stylish, lightweight, and long-lasting accessories, this design offers a rich look without being heavy or uncomfortable. Its elegant finish makes it easy to style with western, ethnic, casual, and party wear outfits. Perfect for daily use, special occasions, and thoughtful gifting.', NULL, NULL, NULL, 'simple', 'instock', TRUE, 'Crafted with high-quality anti-tarnish material and finished with fine detailing, this jewelry is designed to maintain its shine and beauty for a long time. Each piece is carefully made with smooth edges, elegant finishing, and a comfortable lightweight feel. The premium coating helps protect the jewelry from dullness and gives it a lasting golden shine.', 'Avoid perfume and chemicals. Store in a dry pouch or jewelry box after use. Clean with a soft dry cloth to keep your DADSON Jewelry shining longer.', TRUE, TRUE, 'Black Starfish Pendant Set | DADSON Jewelry', 'Stylish black starfish pendant set from DADSON Jewelry. Anti tarnish, trendy, lightweight, and perfect for parties, vacations, and gifting.', 'Black starfish pendant set', 'starfish pendant set, black pendant set, anti tarnish jewelry, beach style jewelry, women necklace set, DADSON Jewelry', '#StarfishPendantSet #BlackJewelry #AntiTarnishJewelry #TrendyJewelry #DADSONJewelry #PartyWearJewelry #VacationJewelry');
